function maxPrices(items, queries) {
  const answer = [];
  const sortedItems = items.map(item => item[0]);
  sortedItems.sort((a, b) => a - b);

  let maxBeauty = 0;
  for (let i = 0; i < sortedItems.length; ++i) {
    maxBeauty = Math.max(maxBeauty, items[i][1]);
    sortedItems[i] = maxBeauty;
  }

  for (const query of queries) {
    const idx = sortedItems.filter(price => price <= query).length - 1;
    answer.push(idx >= 0 ? sortedItems[idx] : 0);
  }

  return answer;
}
