    ```java
import java.util.List;
import java.util.ArrayList;
import java.util.Arrays;
import java.util.Collections;

public List<Integer> maxPrices(List<List<Integer>> items, List<Integer> queries) {
  List<Integer> answer = new ArrayList<>();
  List<Integer> sortedItems = new ArrayList<>();

  for (List<Integer> item : items) {
    sortedItems.add(item.get(0));
  }
  Collections.sort(sortedItems);

  int maxBeauty = 0;
  for (int i = 0; i < sortedItems.size(); ++i) {
    maxBeauty = Math.max(maxBeauty, items.get(i).get(1));
    sortedItems.set(i, maxBeauty);
  }

  for (int j = 0; j < queries.size(); ++j) {
    int idx = Collections.binarySearch(sortedItems, queries.get(j));
    if (idx < 0) {
      idx = -idx - 2;
    }
    answer.add(idx >= 0 ? sortedItems.get(idx) : 0);
  }

  return answer;
}
```


